mapper.select:
SELECT c.id, c.user_id, c.game_id, c.content, c.rating, c.create_time, u.username, u.avatar, g.name as game_name FROM comment c LEFT JOIN user u ON c.user_id = u.id LEFT JOIN game g ON c.game_id = g.id WHERE 1=1
AND c.game_id = #{gameId}
AND c.user_id = #{userId}
ORDER BY c.create_time DESC
